package main

import (
	"github.com/gofiber/fiber/v2"
	"github.com/gofiber/fiber/v2/middleware/logger"
	"github.com/gofiber/fiber/v2/middleware/limiter"
)

func JWTGuard(c *fiber.Ctx) error {
	token := c.Get("Authorization")
	if token == "" {
		return c.SendStatus(fiber.StatusUnauthorized)
	}
	return c.Next()
}

func main() {
	app := fiber.New()

	// Global: runs on every request
	app.Use(logger.New())

	// Public route — no auth middleware
	app.Get("/health", func(c *fiber.Ctx) error {
		return c.SendString("ok")
	})

	// Protected group — JWTGuard + rate limiter scoped here only
	api := app.Group("/api", JWTGuard, limiter.New())
	api.Get("/bytes", func(c *fiber.Ctx) error {
		return c.JSON(fiber.Map{"data": "bytes"})
	})

	app.Listen(":3000")
}

// Fiber handler — N+1 fixed with GORM Preload
app.Get("/posts", func(c *fiber.Ctx) error {
	var posts []Post

	// BAD — 1 + N queries
	// db.Find(&posts)

	// GOOD — 2 queries, joined in memory
	result := db.Preload("Author").Preload("Tags").Find(&posts)
	if result.Error != nil {
		return fiber.ErrInternalServerError
	}
	return c.JSON(posts)
})

type ErrorResponse struct {
	Status  int    `json:"status"`
	Message string `json:"message"`
}

app := fiber.New(fiber.Config{
	ErrorHandler: func(c *fiber.Ctx, err error) error {
		code := fiber.StatusInternalServerError
		msg := "internal server error"
		if e, ok := err.(*fiber.Error); ok {
			code = e.Code
			msg = e.Message
		}
		return c.Status(code).JSON(ErrorResponse{Status: code, Message: msg})
	},
})
app.Use(recover.New())

