import (
	"github.com/gofiber/fiber/v2"
	jwtware "github.com/gofiber/contrib/jwt"
	"github.com/golang-jwt/jwt/v5"
)

func main() {
	app := fiber.New()

	api := app.Group("/api", jwtware.New(jwtware.Config{
		SigningKey: jwtware.SigningKey{Key: []byte("secret")},
	}))

	api.Get("/profile", func(c *fiber.Ctx) error {
		token := c.Locals("user").(*jwt.Token)
		claims := token.Claims.(jwt.MapClaims)
		return c.JSON(fiber.Map{"sub": claims["sub"]})
	})

	app.Listen(":3000")
}

type UserStore interface {
	Find(id string) (*User, error)
}

type UserHandler struct{ store UserStore }

func (h *UserHandler) Get(c *fiber.Ctx) error {
	u, err := h.store.Find(c.Params("id"))
	if err != nil {
		return fiber.ErrNotFound
	}
	return c.JSON(u)
}

type CreatePostRequest struct {
	Title   string `json:"title" validate:"required,min=3,max=120"`
	Content string `json:"content" validate:"required,min=10"`
}

func createPostHandler(v *validator.Validate) fiber.Handler {
	return func(c *fiber.Ctx) error {
		var req CreatePostRequest
		if err := c.BodyParser(&req); err != nil {
			return fiber.NewError(fiber.StatusBadRequest, "invalid JSON")
		}
		req.Title = strings.TrimSpace(req.Title)
		req.Content = strings.TrimSpace(req.Content)
		if err := v.Struct(&req); err != nil {
			return c.Status(fiber.StatusUnprocessableEntity).JSON(fiber.Map{
				"error":  "validation failed",
				"fields": err.(validator.ValidationErrors).Error(),
			})
		}
		return c.Status(fiber.StatusCreated).JSON(fiber.Map{"ok": true})
	}
}

