package main

import (
	"github.com/gofiber/fiber/v2"
	"github.com/robfig/cron/v3"
)

func main() {
	app := fiber.New()
	queue := make(chan string, 100)

	c := cron.New()
	c.AddFunc("@every 1m", func() { queue <- "scheduled-task" })
	c.Start()

	go func() {
		for job := range queue {
			processJob(job)
		}
	}()

	app.Hooks().OnShutdown(func() error {
		c.Stop()
		close(queue)
		return nil
	})

	app.Listen(":3000")
}

package main

import (
	"github.com/ansrivas/fiberprometheus/v2"
	"github.com/gofiber/contrib/otelfiber"
	"github.com/gofiber/fiber/v2"
)

func main() {
	app := fiber.New(fiber.Config{DisableStartupMessage: true})

	app.Use(otelfiber.Middleware("my-service"))

	prom := fiberprometheus.New("my-service")
	prom.RegisterAt(app, "/metrics")
	app.Use(prom.Middleware)

	app.Get("/livez", func(c *fiber.Ctx) error {
		return c.SendStatus(fiber.StatusOK)
	})
	app.Get("/readyz", func(c *fiber.Ctx) error {
		if err := checkDependencies(); err != nil {
			return c.Status(fiber.StatusServiceUnavailable).JSON(fiber.Map{"error": err.Error()})
		}
		return c.SendStatus(fiber.StatusOK)
	})

	app.Listen(":3000")
}

package main

import (
	"github.com/gofiber/fiber/v2"
	"github.com/gofiber/fiber/v2/middleware/cache"
	"github.com/gofiber/fiber/v2/middleware/limiter"
	"github.com/gofiber/fiber/v2/middleware/logger"
	"time"
)

func main() {
	app := fiber.New()

	app.Use(logger.New(logger.Config{
		Format: "[${time}] ${status} ${method} ${path} ${latency}\n",
	}))

	api := app.Group("/api")
	api.Use(limiter.New(limiter.Config{
		Max:        60,
		Expiration: 1 * time.Minute,
	}))
	api.Use(cache.New(cache.Config{
		Expiration:   5 * time.Minute,
		CacheControl: true,
	}))

	api.Get("/bytes", func(c *fiber.Ctx) error {
		return c.JSON(fiber.Map{"data": "cached & rate-limited"})
	})

	app.Listen(":3000")
}
